const expectedSecret = $env.N8N_WEBHOOK_SECRET;
const providedSecret = $json.headers?.['x-servicioscreativos-secret'];

if (!expectedSecret || providedSecret !== expectedSecret) {
  return [{
    json: {
      ok: false,
      error: expectedSecret ? 'Unauthorized.' : 'Workflow secret is not configured.',
      statusCode: expectedSecret ? 401 : 503,
    },
  }];
}

const body = $json.body ?? $json;
const payload = body.payload;

if (body.event !== 'meta_whatsapp_webhook_received' || !payload || typeof payload !== 'object') {
  return [{ json: { ok: false, error: 'Invalid Meta WhatsApp event payload.', statusCode: 400 } }];
}

const entries = Array.isArray(payload.entry) ? payload.entry : [];
const fields = [...new Set(entries.flatMap((entry) =>
  Array.isArray(entry.changes)
    ? entry.changes.map((change) => change?.field).filter(Boolean)
    : []
))];

return [{
  json: {
    ok: true,
    received: true,
    object: payload.object,
    entry_count: entries.length,
    fields,
    received_at: body.received_at ?? new Date().toISOString(),
  },
}];
